parameters.jsCode:
const body = $input.first().json.body;
const options = body.data?.options || [];
const description = options.find(o => o.name === 'description')?.value || 'No description provided';
const logs = options.find(o => o.name === 'logs')?.value || 'No logs provided';
const username = body.member?.user?.username || body.user?.username || 'unknown_user';
const userId = body.member?.user?.id || body.user?.id || 'unknown_id';

return {
  description,
  logs,
  username,
  userId
};

